// // This module implements a 4-bit wide, 2-to-1 demultiplexer. The output M selects between the inputs S and A based on the control signal z. When z is LOW (0), the output M will equal the input S; when z is HIGH (1), the output M will equal the input A.
module top_module(z, S, A, M);input z;
  input [3:0] S, A;
  output [3:0] M;

  assign M = ({4{~z}} & S)|({4{z}} & A);endmodule
